import pytest

def count_vowels(s: str) -> int:
    return sum(1 for c in s.lower() if c in 'aeiou')

class TestCountVowels:
    def test_happy_path(self):
        assert count_vowels("Hello World") == 3
        assert count_vowels("AEIOU") == 5
        assert count_vowels("aeiou") == 5
        assert count_vowels("Python") == 1
        assert count_vowels("Programming") == 3

    def test_empty_string(self):
        assert count_vowels("") == 0

    def test_string_with_no_vowels(self):
        assert count_vowels("Rhythm") == 0
        assert count_vowels("bcdfghjklmnpqrstvwxyz") == 0

    def test_string_with_only_vowels(self):
        assert count_vowels("aeiouaeiou") == 10
        assert count_vowels("AAAAEEEEIIIIOOOOOUUUU") == 20

    def test_string_with_mixed_case(self):
        assert count_vowels("HeLlO wOrLd") == 3
        assert count_vowels("aEiOu") == 5

    def test_string_with_numbers_and_symbols(self):
        assert count_vowels("H3ll0 W0rld!") == 3
        assert count_vowels("A!E@I#O$U%") == 5

    def test_string_with_unicode_characters(self):
        assert count_vowels("你好世界") == 0  # Assuming no vowels in Chinese characters
        assert count_vowels("äöü") == 0 # Assuming no vowels in German characters

    def test_long_string(self):
        long_string = "a" * 1000 + "b" * 1000 + "e" * 1000 + "i" * 1000 + "o" * 1000 + "u" * 1000
        assert count_vowels(long_string) == 6000

    def test_string_with_spaces(self):
        assert count_vowels("  a e i o u  ") == 5
        assert count_vowels(" a e i o u ") == 5
